1	<script setup lang="ts">
2	import { ref, nextTick, onMounted, watch } from 'vue'
3	import { useChatStore } from '@/stores/chat'
4	import ConversationList from '@/components/chat/ConversationList.vue'
5	import MessageBubble from '@/components/chat/MessageBubble.vue'
6	import { Plus, Promotion } from '@element-plus/icons-vue'
7	import type { Conversation } from '@/types'
8	
9	const chatStore = useChatStore()
10	const messageInput = ref('')
11	const messageContainer = ref<HTMLDivElement | null>(null)
12	const inputRef = ref<HTMLTextAreaElement | null>(null)
13	
14	onMounted(() => {
15	  chatStore.loadConversations()
16	})
17	
18	function scrollToBottom() {
19	  nextTick(() => {
20	    if (messageContainer.value) {
21	      messageContainer.value.scrollTop = messageContainer.value.scrollHeight
22	    }
23	  })
24	}
25	
26	watch(
27	  () => chatStore.messages.length,
28	  () => {
29	    scrollToBottom()
30	  },
31	)
32	
33	watch(
34	  () => chatStore.streamingContent,
35	  () => {
36	    scrollToBottom()
37	  },
38	)
39	
40	function handleSelectConversation(conv: Conversation) {
41	  chatStore.selectConversation(conv)
42	}
43	
44	function handleDeleteConversation(convId: number) {
45	  chatStore.deleteConversation(convId)
46	}
47	
48	function handleNewConversation() {
49	  chatStore.newConversation()
50	  messageInput.value = ''
51	}
52	
53	function handleSend() {
54	  const content = messageInput.value.trim()
55	  if (!content || chatStore.streaming) return
56	
57	  messageInput.value = ''
58	  chatStore.sendMessage(content)
59	  scrollToBottom()
60	}
61	
62	function handleKeydown(event: KeyboardEvent) {
63	  if (event.key === 'Enter' && !event.shiftKey) {
64	    event.preventDefault()
65	    handleSend()
66	  }
67	}
68	</script>
69	
70	<template>
71	  <div class="chat-view">
72	    <!-- Sidebar: Conversations -->
73	    <div class="chat-sidebar">
74	      <div class="sidebar-header">
75	        <el-button type="primary" :icon="Plus" class="new-chat-btn" @click="handleNewConversation">
76	          新建对话
77	        </el-button>
78	      </div>
79	      <div class="sidebar-content">
80	        <ConversationList
81	          :conversations="chatStore.conversations"
82	          :active-id="chatStore.currentConversation?.id ?? null"
83	          @select="handleSelectConversation"
84	          @delete="handleDeleteConversation"
85	        />
86	      </div>
87	    </div>
88	
89	    <!-- Main Chat Area -->
90	    <div class="chat-main">
91	      <!-- Messages -->
92	      <div ref="messageContainer" class="message-list">
93	        <div v-if="chatStore.messages.length === 0" class="welcome-section">
94	          <div class="welcome-content">
95	            <h2>欢迎使用智能编程助手</h2>
96	            <p>我可以帮助你解答编程问题、解释代码、推荐学习资源。请在下方输入你的问题开始对话。</p>
97	            <div class="quick-actions">
98	              <el-button
99	                v-for="q in [
100	                  '解释 JavaScript 中的闭包',
101	                  'Python 装饰器怎么用？',
102	                  'React 和 Vue 有什么区别？',
103	                  '如何设计 RESTful API？',
104	                ]"
105	                :key="q"
106	                round
107	                @click="messageInput = q"
108	              >
109	                {{ q }}
110	              </el-button>
111	            </div>
112	          </div>
113	        </div>
114	        <template v-else>
115	          <MessageBubble
116	            v-for="msg in chatStore.messages"
117	            :key="msg.id"
118	            :message="msg"
119	          />
120	        </template>
121	      </div>
122	
123	      <!-- Input -->
124	      <div class="input-area">
125	        <div class="input-container">
126	          <el-input
127	            ref="inputRef"
128	            v-model="messageInput"
129	            type="textarea"
130	            :autosize="{ minRows: 1, maxRows: 6 }"
131	            placeholder="输入你的问题... (Enter 发送, Shift+Enter 换行)"
132	            resize="none"
133	            :disabled="chatStore.streaming"
134	            @keydown="handleKeydown"
135	          />
136	          <el-button
137	            type="primary"
138	            :icon="Promotion"
139	            circle
140	            class="send-btn"
141	            :disabled="!messageInput.trim() || chatStore.streaming"
142	            :loading="chatStore.streaming"
143	            @click="handleSend"
144	          />
145	        </div>
146	        <div class="input-hint">
147	          AI 助手可能会产生不准确的信息，请注意甄别。
148	        </div>
149	      </div>
150	    </div>
151	  </div>
152	</template>
